L "`n=== Copy last license receive lines with full text ==="
$dst='C:\Windows\Temp\AtolLicSvc_copy2.log'
Copy-Item 'C:\ProgramData\ATOL\AtolLicSvc\AtolLicSvc.log' $dst -Force
$enc=[Text.Encoding]::GetEncoding(1251)
$lines=$enc.GetString([IO.File]::ReadAllBytes($dst)) -split "`r?`n"
# find block around last update
for ($i=0; $i -lt $lines.Count; $i++) {
  if ($lines[$i] -match '2026-07-22 10:05') {
    for ($j=[Math]::Max(0,$i-2); $j -le [Math]::Min($lines.Count-1,$i+15); $j++) { L $lines[$j] }
    break
  }
}
